#include <stdlib.h>
#include <stdio.h>
#include <string.h>
#include <math.h>
#include <omp.h>
#include <sys/time.h>

#ifdef TIMING
// timing.h is not provided, implementing tvsub locally
void tvsub(struct timeval *t1, struct timeval *t2, struct timeval *r) {
    r->tv_sec = t1->tv_sec - t2->tv_sec;
    r->tv_usec = t1->tv_usec - t2->tv_usec;
    if (r->tv_usec < 0) {
        r->tv_sec--;
        r->tv_usec += 1000000;
    }
}
#endif

#define MAX_THREADS_PER_BLOCK 512

int no_of_nodes;
int edge_list_size;
FILE *fp;

#ifdef TIMING
struct timeval tv;
struct timeval tv_total_start, tv_total_end;
struct timeval tv_h2d_start, tv_h2d_end;
struct timeval tv_d2h_start, tv_d2h_end;
struct timeval tv_kernel_start, tv_kernel_end;
struct timeval tv_mem_alloc_start, tv_mem_alloc_end;
struct timeval tv_close_start, tv_close_end;
float init_time = 0, mem_alloc_time = 0, h2d_time = 0, kernel_time = 0,
      d2h_time = 0, close_time = 0, total_time = 0;
#endif


struct Node
{
	int starting;
	int no_of_edges;
};

void BFSGraph(int argc, char** argv);

int main( int argc, char** argv) 
{
	no_of_nodes=0;
	edge_list_size=0;
	BFSGraph( argc, argv);
}

void Usage(int argc, char**argv){

fprintf(stderr,"Usage: %s <input_file>\n", argv[0]);

}

void BFSGraph( int argc, char** argv) 
{

    char *input_f;
	if(2 != argc){
	Usage(argc, argv);
	exit(0);
	}

	input_f = argv[1];
	printf("Reading File\n");

	fp = fopen(input_f,"r");
	if(!fp)
	{
		printf("Error Reading graph file\n");
		return;
	}

	int source = 0;

	fscanf(fp,"%d",&no_of_nodes);

	int num_of_blocks = 1;
	int num_of_threads_per_block = no_of_nodes;


	if(MAX_THREADS_PER_BLOCK < no_of_nodes)
	{
		num_of_blocks = (int)ceil(no_of_nodes/(double)MAX_THREADS_PER_BLOCK); 
		num_of_threads_per_block = MAX_THREADS_PER_BLOCK; 
	}


	Node* h_graph_nodes = (Node*) malloc(sizeof(Node)*no_of_nodes);
	bool *h_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_updating_graph_mask = (bool*) malloc(sizeof(bool)*no_of_nodes);
	bool *h_graph_visited = (bool*) malloc(sizeof(bool)*no_of_nodes);

	int start, edgeno;   

	for( unsigned int i = 0; no_of_nodes > i; i++) 
	{
		fscanf(fp,"%d %d",&start,&edgeno);
		h_graph_nodes[i].starting = start;
		h_graph_nodes[i].no_of_edges = edgeno;
		h_graph_mask[i]=false;
		h_updating_graph_mask[i]=false;
		h_graph_visited[i]=false;
	}


	fscanf(fp,"%d",&source);
	source=0;


	h_graph_mask[source]=true;
	h_graph_visited[source]=true;

	fscanf(fp,"%d",&edge_list_size);

	int id,cost;
	int* h_graph_edges = (int*) malloc(sizeof(int)*edge_list_size);
	for(int i=0; edge_list_size > i ; i++)
	{
		fscanf(fp,"%d",&id);
		fscanf(fp,"%d",&cost);
		h_graph_edges[i] = id;
	}

	if(fp)
		fclose(fp);    

	printf("Read File\n");

#ifdef  TIMING
    gettimeofday(&tv_total_start, NULL);
#endif

	// CUDA mallocs removed, using host memory directly
	// d_graph_nodes -> h_graph_nodes
	// d_graph_edges -> h_graph_edges
	// d_graph_mask -> h_graph_mask
	// d_updating_graph_mask -> h_updating_graph_mask
	// d_graph_visited -> h_graph_visited

	printf("Copied Everything to GPU memory\n");

	// Grid and threads setup removed for OpenMP

	int k=0;
	printf("Start traversing the tree\n");
	bool stop;

	do
	{

		stop=false;
#ifdef  TIMING
		gettimeofday(&tv_h2d_start, NULL);
#endif
		// cudaMemcpy( d_over, &stop, sizeof(bool), cudaMemcpyHostToDevice) ;
		// In OpenMP, stop is a host variable, no copy needed
#ifdef  TIMING
		gettimeofday(&tv_h2d_end, NULL);
		tvsub(&tv_h2d_end, &tv_h2d_start, &tv);
		h2d_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		// Kernel logic inline
		#pragma omp parallel for
		for (int i = 0; i < no_of_nodes; i++) {
            if (h_graph_mask[i]) {
                h_graph_mask[i] = false;
                for (int j = h_graph_nodes[i].starting; j < h_graph_nodes[i].starting + h_graph_nodes[i].no_of_edges; j++) {
                    int neighbor = h_graph_edges[j];
                    if (!h_graph_visited[neighbor]) {
                        h_cost[neighbor] = h_cost[i] + 1;
                        h_updating_graph_mask[neighbor] = true;
                    }
                }
            }
        }

		// Kernel2 logic inline
		#pragma omp parallel for
		for (int i = 0; i < no_of_nodes; i++) {
            if (h_updating_graph_mask[i]) {
                h_graph_mask[i] = true;
                h_graph_visited[i] = true;
                stop = true;
                h_updating_graph_mask[i] = false;
            }
        }

#ifdef  TIMING
		// cudaDeviceSynchronize(); removed, OpenMP implies sync
		gettimeofday(&tv_kernel_end, NULL);
		tvsub(&tv_kernel_end, &tv_h2d_end, &tv);
		kernel_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		// cudaMemcpy( &stop, d_over, sizeof(bool), cudaMemcpyDeviceToHost) ;
		// stop is already updated by Kernel2 loop
#ifdef  TIMING
		gettimeofday(&tv_d2h_end, NULL);
		tvsub(&tv_d2h_end, &tv_kernel_end, &tv);
		d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif

		k++;
	}
	while(stop);


	printf("Kernel Executed %d times\n",k);


#ifdef  TIMING
	gettimeofday(&tv_d2h_start, NULL);
#endif
	// cudaMemcpy( h_cost, d_cost, sizeof(int)*no_of_nodes, cudaMemcpyDeviceToHost) ;
	// h_cost is already updated on host
#ifdef  TIMING
	gettimeofday(&tv_d2h_end, NULL);
	tvsub(&tv_d2h_end, &tv_d2h_start, &tv);
	d2h_time += tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
#endif


	FILE *fpo = fopen("result.txt","w");
	for(int i=0;no_of_nodes > i;i++)
		fprintf(fpo,"%d) cost:%d\n",i,h_cost[i]);
	fclose(fpo);
	printf("Result stored in result.txt\n");



	free( h_graph_nodes);
	free( h_graph_edges);
	free( h_graph_mask);
	free( h_updating_graph_mask);
	free( h_graph_visited);
	free( h_cost);
#ifdef  TIMING
    gettimeofday(&tv_close_start, NULL);
#endif
	// cudaFree removed
	// d_graph_nodes, d_graph_edges, d_graph_mask, d_updating_graph_mask, d_graph_visited, d_cost were host pointers in OpenMP version, already freed above or not allocated separately
	// In original CUDA code, d_ were separate allocations. In OpenMP, we used h_ for everything.
	// To match original flow exactly regarding free calls (semantic), we just free h_.
	// The original cudaFree calls are removed.

#ifdef  TIMING
	gettimeofday(&tv_close_end, NULL);
	tvsub(&tv_close_end, &tv_close_start, &tv);
	close_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;
	tvsub(&tv_close_end, &tv_total_start, &tv);
	total_time = tv.tv_sec * 1000.0 + (float) tv.tv_usec / 1000.0;

	printf("Init: %f\n", init_time);
	printf("MemAlloc: %f\n", mem_alloc_time);
	printf("HtoD: %f\n", h2d_time);
	printf("Exec: %f\n", kernel_time);
	printf("DtoH: %f\n", d2h_time);
	printf("Close: %f\n", close_time);
	printf("Total: %f\n", total_time);
#endif
}

